<?php

use App\Models\User;
use Illuminate\Database\Migrations\Migration;
use Illuminate\Database\Schema\Blueprint;
use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Schema;

/**
 * Adds the team key to the permission tables so roles can be scoped per team.
 *
 * Adapted from the stub shipped by spatie/laravel-permission
 * (database/migrations/add_teams_fields.php.stub, generated by
 * `php artisan permission:setup-teams`). Two deliberate departures from it, both
 * about the pivot tables, are marked below.
 *
 * Idempotent by column check, and that is load-bearing rather than defensive:
 * create_permission_tables consults permission.teams at run time, so now the
 * flag is on, a fresh database gets these columns from that migration and never
 * reaches the bodies here. An existing database gets them here. The two paths
 * have to converge on the same schema.
 */
