{
    public function up(): void
    {
        $tableNames = config('permission.table_names');
        $columnNames = config('permission.column_names');
        $pivotRole = $columnNames['role_pivot_key'] ?? 'role_id';
        $pivotPermission = $columnNames['permission_pivot_key'] ?? 'permission_id';
        $teamKey = $columnNames['team_foreign_key'] ?? null;

        if (! config('permission.teams')) {
            return;
        }

        throw_if(empty($tableNames), 'Error: config/permission.php not loaded. Run [php artisan config:clear] and try again.');
        throw_if(empty($teamKey), 'Error: team_foreign_key on config/permission.php not loaded. Run [php artisan config:clear] and try again.');

        // Role definitions stay global by default. A null team means the role
        // exists in every team, which is what the seeded super_admin is and
        // must remain — scoping it would strip administrators of every team but
        // whichever one happened to be current when the seeder ran.
        if (! Schema::hasColumn($tableNames['roles'], $teamKey)) {
            Schema::table($tableNames['roles'], function (Blueprint $table) use ($teamKey) {
                $table->unsignedBigInteger($teamKey)->nullable()->after('id');
                $table->index($teamKey, 'roles_team_foreign_key_index');

                $table->dropUnique('roles_name_guard_name_unique');
                $table->unique([$teamKey, 'name', 'guard_name']);
            });
        }

        $this->addTeamToPivot(
            $tableNames['model_has_permissions'],
            $teamKey,
            $pivotPermission,
            $columnNames['model_morph_key'],
            $tableNames['permissions'],
            'model_has_permissions_permission_model_type_primary',
            'model_has_permissions_team_foreign_key_index',
        );

        $this->addTeamToPivot(
            $tableNames['model_has_roles'],
            $teamKey,
            $pivotRole,
            $columnNames['model_morph_key'],
            $tableNames['roles'],
            'model_has_roles_role_model_type_primary',
            'model_has_roles_team_foreign_key_index',
        );

        app('cache')
            ->store(config('permission.cache.store') != 'default' ? config('permission.cache.store') : null)
            ->forget(config('permission.cache.key'));
    }

    /**
     * Assignments, unlike definitions, must name a team: the team key joins the
     * primary key, so it cannot be null.
     *
     * FIRST DEPARTURE FROM THE STUB. It adds this column with a hardcoded
     * default of 1, which writes every pre-existing grant to whichever team
     * happens to hold id 1 — a team that need not exist, and whose members need
     * not include the people being granted roles in it. That is the shape of
     * invention this codebase has been removing elsewhere, so it is not used.
     *
     * Instead each existing grant is backfilled to the team its holder was last
     * working in, which is the only team the row carries any evidence for. This
     * narrows previously-global grants to a single team. That is a real change
     * in behaviour and the one the ticket asks for: it removes access rather
     * than inventing it, and an administrator who needs the role in a second
     * team can be granted it there.
     *
     * SECOND DEPARTURE. If any row cannot be resolved that way the migration
     * fails rather than guessing. A grant nobody can attribute to a team is
     * exactly the thing not to paper over.
     */
