        string $table,
        string $teamKey,
        string $pivotKey,
        string $morphKey,
        string $referencedTable,
        string $primaryName,
        string $indexName,
    ): void {
        if (Schema::hasColumn($table, $teamKey)) {
            return;
        }

        Schema::table($table, function (Blueprint $table) use ($teamKey, $indexName) {
            $table->unsignedBigInteger($teamKey)->nullable();
            $table->index($teamKey, $indexName);
        });

        // A correlated subquery rather than an UPDATE ... JOIN: SQLite cannot
        // reference a joined table on the right of SET, so the join form works
        // on MariaDB and fails on the test database. Both dialects accept this.
        //
        // Table names are interpolated, so they are prefixed by hand — the
        // query builder prefixes the tables it is given but not raw fragments,
        // and the two must agree on any install that sets one.
        $prefix = DB::getTablePrefix();
        $users = $prefix.'users';
        $teams = $prefix.'teams';
        $members = $prefix.'team_user';
        $pivot = $prefix.$table;

        // The team must still exist and the holder must still be able to reach
        // it. current_team_id outlives both in this application — removeUser()
        // and a bare detach() leave the column pointing at a team the user is
        // no longer in, which TenantAccessControlTest covers directly — so
        // taking it at face value would scope a grant to a team its holder
        // cannot open, leaving a live row that nothing displays and nobody can
        // revoke. Rows that fail this stay null and are refused below.
        //
        // Reachable means owner OR member: Jetstream does not put an owner in
        // team_user, so a membership-only test would reject every personal
        // team, which is most of them.
        DB::table($table)
            ->where('model_type', User::class)
            ->update([
                $teamKey => DB::raw(
                    "(select u.current_team_id from {$users} u"
                    ." inner join {$teams} t on t.id = u.current_team_id"
                    ." where u.id = {$pivot}.{$morphKey}"
                    .' and (t.user_id = u.id or exists ('
                    ."select 1 from {$members} m where m.team_id = t.id and m.user_id = u.id)))"
