        throw_if($unresolved > 0, new RuntimeException(
            "Cannot scope {$unresolved} row(s) in {$table} to a team: the holder has no current team, "
            .'or is not a user. Assign each holder a team, or delete the grants, then re-run this migration.'
        ));

