            $table->unsignedBigInteger($teamKey)->nullable(false)->change();

            // SQLite has no ALTER for foreign keys; the driver rebuilds the
            // whole table instead, which carries the constraint across.
            if (DB::getDriverName() !== 'sqlite') {
                $table->dropForeign([$pivotKey]);
            }

            $table->dropPrimary();
            $table->primary([$teamKey, $pivotKey, $morphKey, 'model_type'], $primaryName);

            if (DB::getDriverName() !== 'sqlite') {
                $table->foreign($pivotKey)->references('id')->on($referencedTable)->cascadeOnDelete();
            }
        });
    }

    public function down(): void {}
};
